INSERT INTO `messages` VALUES (42,19,1,2,'היי\nאני מעוניין לקנות אופנוע','2026-06-12 17:29:47'),(43,19,2,1,'היי! זה נהדר שאתה מתעניין לקנות אופנוע. איזה סוג אופנוע אתה מחפש? יש לך תקציב מסוים או צורך מסוים שאתה רוצה למלא באופנוע? אני כאן כדי לעזור!','2026-06-12 17:29:49'),(44,20,1,2,'היי\nאני מעוניין לקנות אופנוע','2026-06-12 17:29:51'),(45,20,2,1,'היי! זה נהדר לשמוע שאתה מתעניין לקנות אופנוע. יש כמה דברים שיכולים לעזור לך להתחיל:\n\n1. **סוג האופנוע**: חשבתי על איזה סוג אופנוע אתה מעוניין? יש אופנועים לדו-שימוש (שטח וכביש), אופנועי ספורט, אופנועים קלאסיים, ואחרים.\n\n2. **תקציב**: מה התקציב שלך? ישנם אופנועים בכל טווחי המחירים.\n\n3. **ניסיון**: יש לך ניסיון לפני זה? אם אתה רוכב חדש, אולי כדאי לשקול אופנוע קטן יותר ומתחיל.\n\n4. **ציוד בטיחות**: חשוב להשקיע גם בציוד בטיחות כמו קסדה, מגני גוף, כפפות וחליפת רכיבה.\n\nאם תוכל לספק יותר פרטים, אשמח לעזור לך יותר!','2026-06-12 17:29:57'),(46,19,3,2,'משהו בסגנון ADVENTUER ','2026-06-12 17:30:59'),(47,19,4,1,'יופי! אופנועי Adventure (או ADV) הם בחירה מצוינת אם אתה מחפש שילוב של רכיבה בשטח ובכביש. הם בדרך כלל מצוידים בתכונות שמאפשרות להם להתמודד עם מגוון תנאי רכיבה.\n\nכשאתה בוחר אופנוע Adventure, יש כמה דברים שחשוב לשקול:\n\n1. **נפח מנוע**: אופנועים קטנים יותר (כמו 500-700 סמ\"ק) בדרך כלל יותר קלים לשימוש ומומלצים לרוכבים מתחילים, בעוד שאופנועים עם מנוע בנפח גדול יותר (800 סמ\"ק ומעלה) מציעים ביצועים טובים יותר בכביש ובשטח.\n\n2. **משקל**: ודא que האופנוע לא כבד מדי עבורך, במיוחד אם אתה מתכוון לרכב בשטח.\n\n3. **נוחות רכיבה**: נסה לרכב על כמה דגמים שונים כדי לראות איזה מהם הכי נוח לך.\n\n4. **טכנולוגיה**: טכנולוגיות כמו ABS, בקרת אחיזה ו-ride modes יכולים לשפר את חווית הרכיבה.\n\n5. **שירות ותמיכה**: צור קשר עם נותני שירות באזור שלך כדי לוודא שיש תמיכת שירות זמינה עבור הדגם שאתה שוקל.\n\nהדגמים הפופולריים בקטגוריית Adventure כוללים:\n\n- BMW GS סדרה (כמו R1250GS)\n- KTM 1290 Super Adventure\n- Honda Africa Twin\n- Yamaha Tenere 700\n- Triumph Tiger\n\nאם יש לך שאלות נוספות או צריך מידע על דגם מסוים, אל תהסס לשאול!','2026-06-12 17:31:05'),(52,23,1,2,'כמה מים צריך עץ מנגו','2026-06-13 22:16:01'),(55,23,2,1,'עץ מנגו זקוק למים בכמויות שיכולות להשתנות בהתאם לגיל העץ, למזג האוויר ולסוג האדמה. עשרות השנים הראשונות עץ מנגו צעיר יכול לדרוש השקיה קבועה כדי להתבסס טוב. \n\nעקרונית, בחודשי הקיץ החמים, יש להשקות עץ מנגו לפחות פעם בשבוע, ואולי יותר בתנאים מאוד יבשים. בעונות הגשומות, תהליך השורשים של העץ קולט מים מהקרקע, ואין צורך להשקות.\n\nבוגרים, עץ מנגו יכול להסתדר גם עם פחות מים, אך חשוב להקפיד על השקיה מספקת בתקופות של יובש. מומלץ לבדוק את לחות האדמה ולהשקות לפי הצורך.\n\nכמובן, השתדל להימנע מהשקיה יתרה, מכיוון שזה עלול לגרום לרקבון שורשים.','2026-06-13 22:16:05'),(56,23,3,2,'מה ההסדל בן ליצי למנגו','2026-06-13 22:17:07'),(57,23,4,1,'ליצי ומנגו הם שני סוגי פרי שונים, וכל אחד מהם מגיע ממין ועץ שונים. הנה כמה הבדלים מרכזיים ביניהם:\n\n1. **מוצא**:\n   - **ליצי** (Litchi chinensis) הוא פרי שמקורו בדרום סין ובאזורים טרופיים נוספים באסיה.\n   - **מנגו** (Mangifera indica) הוא פרי שמקורו בדרום אסיה, בעיקר בהודו ובפרס.\n\n2. **מאפייני הפרי**:\n   - **ליצי**: \n     - בעל קליפה אדומה או ורודה, רכה ועטופה בבשר פירות לבן ושקוף.\n     - הטעם מתוק עם טעמים פרחוניים, והמרקם רך.\n   - **מנגו**:\n     - קליפה עורית שעשויה להיות ירוקה, צהובה או אדומה, תלוי בזן.\n     - בשר פרי עבה, עסיסי ומתקתק, עם גרעין גדול במרכז.\n\n3. **עונה**:\n   - **ליצי**: בדרך כלל מתבצע בעונת הקיץ, והוא זמין בשווקים בעיקר במאי-יולי.\n   - **מנגו**: גם המנגו זמין בעונת הקיץ, אך הוא נמצא בשווקים לאורך חודשים רבים, עם זנים שונים בכל עונה.\n\n4. **ערכים תזונתיים**:\n   - שני הפרים הם עשירים בוויטמינים, ומזינים, אך בעיות שונות. הליצי מכיל בעיקר ויטמין C, ואילו המנגו מכיל כמויות גבוהות של ויטמינים A ו-C.\n\n5. **שימושים**:\n   - **ליצי**: בדרך כלל נאכל טרי, אך גם משתמשים בו בפתיחות, קינוחים או במיצים.\n   - **מנגו**: נפוץ כאוכל טרי, וכמו כן בו השתמשים להכנת שייקים, סלטים, ריבות, רטבים, ועוד.\n\nלסיכום, למרות ששני הפירות הם מתוקים וטעימים, הם שונים באופן מהותי במוצא, במראה, בטעם ובשימושים הקולינריים שלהם.','2026-06-13 22:17:17'),(58,23,5,2,'הליצח לא מוציא פירות','2026-06-13 22:22:29'),(59,23,6,1,'אם עץ הליצי לא מוציא פירות, יש מספר סיבות אפשריות לכך. הנה כמה מהן:\n\n1. **גיל העץ**: ליצי לוקח זמן להבשיל ולהתחיל להניב פירות. עץ ליצי צעיר עשוי לקחת מספר שנים (בדרך כלל בין 3 ל-5 שנים או יותר) עד שייתחיל להניב פירות.\n\n2. **תנאי אקלים**: הליצי זקוק לתנאים טרופיים או סוב-טרופיים עם חום ולחות. טמפרטורות נמוכות או תנאים קרים עשויים להשפיע על הפריה.\n\n3. **השקיה**: עץ הליצי זקוק למים, אך יש להקפיד לא להשקות יותר מדי. השקיה לא מספקת או השקיה יתרה עלולה לפגוע בפרי.\n\n4. **הצטברות חומרים מזינים**: יש צורך לטפח את העץ בתמיסות דשן מתאימות. מחסור במזין מסוים יכול להשפיע על היכולת של העץ להניב פרי.\n\n5. **פריחה ופריה**: אם לא היו מספיק חרקים Pollinators כמו דבורים באזור שלך, ייתכן שהפריחה לא התרחשה ולכן לא התקבלו פירות.\n\n6. **תחזוקה**: אם לא מבצעים גיזום סדיר והסרת ענפים יבשים או חולים, זה יכול להשפיע על בריאות העץ.\n\n7. **מחלות ומזיקים**: העץ עשוי להיות מושפע ממחלות או מזיקים שנוגעים בפריחה ובפרי.\n\nאם עץ הליצי שלך לא הניב פירות במשך זמן ממושך, כדאי לבדוק את התנאים הסביבתיים, להשקיע בטיפול הנכון בעץ או להתייעץ עם גנן מקצועי על מנת להבין את הסיבות המדויקות למצב.','2026-06-13 22:22:37'),(60,23,7,2,'איזה בעל חיים אוכל פסיפלורה ישירות מהשיח','2026-06-13 22:23:47'),(61,23,8,1,'פסיפלורה, או בשמה הנוסף \"פרי התשוקה\" (Passiflora edulis), היא פרי שמושך שונים בעלי חיים, שמאכילים את עצמם מהשיח. כמה מבעלי החיים הידועים שאוכלים פסיפלורה ישירות מהצמח כוללים:\n\n1. **ציפורים**: במיוחד ציפורים כמו תוכים, עורבים וציפורי שיר שונות. הן מתעניינות בפרי בשל ומלקקות את הבשר ומהן את הזרעים.\n\n2. **קופים**: קופים ועצלים הם גם בעלי חיים שנמצאים באזורים טרופיים ואוכלים את פרי הפסיפלורה.\n\n3. **חרקים**: גם חרקים שונים עלולים לאכול את הפרי, אם כי זה לא נפוץ.\n\nבהתחשב בטעמו המתוק והעסיסי של הפרי, פסיפלורה היא יעד מועדף לבעלי חיים חקלאיים וגם לצרכים קופסתיים בברים ועבור השוק.','2026-06-13 22:23:51'),(62,23,9,2,'ליצי מחוייב בעורלה ?','2026-06-13 22:25:13'),(63,23,10,1,'ליצי נחשב לפרי שמחויב בעורלה לפי ההלכה היהודית. עורלה היא מצווה שמחייבת את המגדלים והצרכנים לנהוג בפרי שניטע אחרי גיל 3 שנים, וחייבים להסיר ממנו את הפרי שנמצא על העץ במשך שלוש השנים הראשונות.\n\nלפי ההלכה, יש לנהוג בעורלה גם בפרי שנמלח (מם) בעציצים ובשדה, והמצווה חלה על כל הפירות שנאכלים. לכן, אם אתה מתכוון לאכול ליצי שהגיע מישראל (או שגדל על פי החוק המקומי), יש לשים לב אם הוא נידון בעורלה או לא.\n\nאם אתה קונה ליצי שנגדל בארץ, כדאי לבדוק אם יש סימון או מידע לגבי העורלה. במקרים של פירות מייבוא, לרוב יש לקחת בחשבון את תקנות העורלה של צריכת הפירות בארץ.','2026-06-13 22:25:17'),(64,24,1,2,'זמני כניסת שבת','2026-06-13 22:27:36'),(65,24,2,1,'מכיוון שזמני כניסת שבת משתנים ממקום למקום ומתקופה לתקופה, אני ממליץ לבדוק את המידע באתרי היהדות או באפליקציות שמספקות זמני תפילות וזמני כניסת שבת. אם אתה מתעניין בזמני כניסה לשבת בעיר ספציפית, אתה מוזמן לכתוב לי את שם העיר ואנסה לעזור כמיטב יכולתי.','2026-06-13 22:27:38'),(66,24,3,2,'יבנה','2026-06-13 22:27:58'),(67,24,4,1,'זמני כניסת שבת משתנים מדי שבוע ולכן יש לבדוק את המידע באופן עדכני. עם זאת, בדרך כלל, זמני כניסת שבת ביבנה הם בסביבות:\n\n- **זמן כניסת שבת**: בדרך כלל בין 18:30 ל-19:10, תלוי במועד בשנה.\n- **זמן خروج שבת**: בדרך כלל בין 19:50 ל-20:15.\n\nמומלץ לבדוק את המידע באתרים או באפליקציות ייעודיות, כמו \"זמני תפילות\" או \"אביר יעקב\", כדי לקבל את המידע המדויק והעדכני ביותר לכל שבוע.','2026-06-13 22:28:01'),(68,25,1,2,'איך מכינים שניצלים','2026-06-13 22:51:59'),(69,25,2,1,'כדי להכין שניצלים, תצטרך את המרכיבים והכלים הבאים:\n\n### מרכיבים:\n1. חזה עוף או חזה תרנגולת\n2. מלח\n3. פלפל שחור\n4. קמח (לגרסה היבשה)\n5. ביצים\n6. פנקו (או Breadcrumbs) – פירורי לחם\n7. שמן לטיגון\n\n### כלי עבודה:\n1. פטיש שניצל או כלי דמוי פטיש\n2. צלחת שטוחה או קופסה לניפוי\n3. קופסה נוספת להכנת הבצ batter\n4. מחבת שטוחה לטיגון\n5. מגבת נייר לסינון שומן\n\n### הוראות הכנה:\n1. **הכנת חזה העוף**: חתוך את חזית העוף לפרוסות דקות בעובי 1-2 ס\"מ. אם רוצים, ניתן להכות עם פטיש שניצל כדי להכות את הפרוסות ולהפוך אותן לדקות יותר.\n   \n2. **תיבול**: מתבלים את נתחי העוף במלח ופלפל משני הצדדים.\n\n3. **טבילת השניצלים**:\n   - **קמח**: שים קמח בצלחת שטוחה. טבל את כל נתחי העוף בקמח, עד שהקמח דבק לכל הפנים.\n   - **ביצים**: בקופסה נפרדת, שוברים ביצים וטורפים אותן. טבל את נתחי העוף בקערת הביצים כך שהביצה תכסה את כל הנתח.\n   - **פנקו**: לאחר מכן, טבל את נתחי העוף בפירורי לחם (פנקו), כך שהפירורים ידבקו היטב.\n\n4. **טיגון**: מחממים שמן במחבת על חום בינוני-גבוה. ברגע שהשמן חם, מניחים את נתחי השניצל במחבת בצורה זהירה. טגנים כ-3-4 דקות מכל צד, עד שהשניצלים זהובים וקריספיים.\n\n5. **סינון שומן**: כאשר השניצלים מוכנים, מעבירים אותם למגבת נייר לסינון השומן.\n\n6. **הגשה**: מגישים עם תוספות כמו תפוחי אדמה, סלט, או רטבים מגוונים.\n\nבתיאבון!','2026-06-13 22:52:06'),(70,25,3,2,'איזה עוד תוספות אפשריות לצד השניצל?','2026-06-13 22:53:02'),(71,25,4,1,'לשניצלים ניתן להוסיף מגוון רחב של תוספות, שיכולות לשדרג את הארוחה ולהתאים לטעמים שונים. הנה כמה רעיונות:\n\n1. **תפוחי אדמה**:\n   - תפוחי אדמה צלויים בתנור עם תיבול (מלח, פלפל, שמן זית ותבלינים).\n   - פירה תפוחי אדמה.\n   - צ\'יפס או פוטטו פריזאי (תפוחי אדמה מטוגנים).\n\n2. **סלטים**:\n   - סלט ירקות טרי (עגבניות, מלפפונים, חסה, בצל).\n   - סלט טונה או סלט ביצים.\n   - סלט קולבר או סלט כרוב עם רוטב טעים.\n\n3. **רטבים**:\n   - רוטב tzatziki (יוגורט עם מלפפון ושום).\n   - רוטב חריף או רוטב צ\'ילי.\n   - מיונז, קצפת שמנת או רוטב שום.\n\n4. **גרגרים**:\n   - אורז (לבן, פרסי או עם ירקות).\n   - קוסקוס או קינואה.\n\n5. **ירקות בגריל או מוקפצים**:\n   - שום סוג של ירקות כמו קישואים, פלפלים, גזר וברוקולי.\n   - ירקות מוקפצים עם רוטב סויה.\n\n6. **לחם**:\n   - פוקאצ\'ה או לחם פריך.\n   - פיתה או בייגלה.\n\n7. **תוספות נוספות**:\n   - פרוסות אבוקדו.\n   - חמוצים שונים.\n   - תפוחי אדמה מבושלים או רגבים.\n\nכל תוספת תביא טעמים, צבעים ומרקמים שונים לארוחה שלכם, כך שתוכלו לגוון ולהתאים את השניצל לטעמים האישיים שלכם. בתיאבון!','2026-06-13 22:53:09'),(72,20,3,2,'דו שימושי','2026-06-14 23:23:23'),(73,20,4,1,'אופנוע דו-שימושי הוא בחירה מצוינת, כי הוא מתאים גם לרכיבה בעיר וגם לנסיעות בשטח. הנה כמה פרטים ועצות שיכולים לעזור לך בבחירה:\n\n### 1. **דגמים פופולריים**:\n   - **Kawasaki Versys**: אופנוע נוח לנסיעות ארוכות החשוב למעשה עם יכולות שטח טובות.\n   - **Honda CRF250L**: אופנוע קל וקומפקטי, מאוד ידידותי לרוכבים חדשים.\n   - **Yamaha Tenere 700**: אופנוע שיכולת השטח שלו גבוהה, וגם מצוין לנסיעות כביש.\n   - **BMW GS טווח 310 / 850**: אופנועים איכותיים ומוכרים בשוק הדו-שימושי, יש להם מאפיינים מעולים לנסיעות ארוכות.\n\n### 2. **מאפיינים חשובים**:\n   - **משקל**: אם אתה רוכב חדש, כדאי לבחור באופנוע קל שיכול להיות יותר נוח לשליטה.\n   - **נוחות רכיבה**: חשוב לבדוק את Comfort המושב, בעיקר אם אתה מתכנן לנסוע מרחקים ארוכים.\n   - **יכולת שטח**: חפש אופנוע עם צמיגים המתאימים לתנאי שטח ושמונה גבוהה.\n\n### 3. **ציוד ואביזרים**:\n   - **קסדה**: חובה לכל רוכב – כדאי להשקיע בקסדה איכותית.\n   - **מגני גוף**: כולל מגני ברכיים, מרפקים וחליפת רכיבה.\n   - **תיקים ואחסון**: חשוב שיהיה לך מקום לאחסון כשאתה נוסע בשבילי שטח.\n\n### 4. **רגולציה ורישוי**:\n   - ודא שאתה מודע לכל דרישות הרישוי באזור שלך לרכישת אופנוע, כולל רישיונות, ביטוח וכו\'.\n\nאם יש לך שאלות נוספות או דגמים מסוימים שאתה רואה, אני כאן לעזור!','2026-06-14 23:23:34'),(74,20,5,2,'משהו באיזור 800 סמק ','2026-06-14 23:31:17'),(75,20,6,1,'אופנועים בגודל 800 סמ\"ק הם בחירה מצוינת לקטגוריית הדו-שימושי. הם מציעים כוח טוב לא רק לנסיעות בכביש אלא גם לנסיעות בשטח. הנה כמה דגמים פופולריים ומומלצים:\n\n### 1. **Yamaha Tenere 700**\n   - מכונת דו-שימושי איכותית המתאימה לשטח ודרך אספלט.\n   - כוח, אמינות, וחווית רכיבה מצוינת בשני סוגי השטח.\n   - משקל סביר, קלה לתמרון, עם שינויים טובים בשטח.\n\n### 2. **BMW F 850 GS**\n   - אופנוע פופולרי מאוד בקטגוריית הדו-שימושי.\n   - מציע יכולות טובות בשטח ונוחות טובה בכביש.\n   - מערכת מתקדמת של מומחה ביטיחות, בטיחות, ויכולת טיול.\n\n### 3. **Kawasaki Versys 650**\n   - אופנוע נוח לנסיעות ארוכות, עם בטיחות ויכולת שטח סבירה.\n   - ניתן לשדרגו בכמה אופציות כדי להתאים לרכיבה בשטח.\n\n### 4. **Honda Africa Twin (דגם 850)**\n   - אופנוע המפורסם בזכות יכולות השטח שלו, נחשב לאגדה בתחום.\n   - יחסית קל לתפעול ובעל טכנולוגיה מתקדמת.\n\n### 5. **Suzuki V-Strom 650**\n   - אופנוע עם נוחות גבוהה לרכיבה ארוכת טווח ויכולת שטח סבירה.\n   - מערכת נהדרת, אמינות גבוהה.\n\n### טיפים לרכישה:\n- **נסיעת מבחן**: לפני שאתה מחליט, חשוב לערוך נסיעת מבחן כדי לראות מה נוח לך ומה מתאים לסגנון הרכיבה שלך.\n- **שירות ותחזוקה**: בדוק את הזמינות של שירותים וחלקי חילוף לאופנוע שאתה שוקל לקנות.\n- **ביטוח**: קיים באופנועים דו-שימושיים תקציב ביטוח שונה – כדאי לבדוק מחירים לפני הקנייה.\n\nאם יש לך שאלות נוספות או אם אתה שוקל דגם מסוים, אני כאן לעזור!','2026-06-14 23:31:45'),(76,20,7,2,'מיגון כבר יש\nמחפש משהו יחסית זול','2026-06-14 23:35:08'),(77,20,8,1,'אם יש לך כבר מיגון ואתה מחפש אופנוע דו-שימושי בסביבות 800 סמ\"ק בתקציב יחסית זול, יש כמה דגמים שיכולים להתאים. חשוב גם להתחשב בשוק היד השנייה, שם אפשר למצוא עסקות טובות. הנה רשימה של אופנועים שיכולים להתאים:\n\n### אופנועים דו-שימושיים בתקציב נמוך יחסית:\n\n1. **Kawasaki Versys 650 (אזור ה-2010-2015)**:\n   - אופנוע מאוד נוח עם יכולות שטח וספורט טובים.\n   - מערכת אמינה עם תחזוקה נוחה, לרוב ניתן למצוא במחירים סבירים בשוק היד שנייה.\n\n2. **Suzuki V-Strom 650 (אזור ה-2010-2015)**:\n   - אופנוע עם ציון גבוה בנוחות רכיבה, יכולת שטח טובה ושימוש יומיומי.\n   - עקוב אחר דגמים משומשים במצב טוב.\n\n3. **Yamaha XT660R**:\n   - אופנוע דו-שימושי חזק ומוכר עם יכולת טובה בשטח.\n   - זמין במחירים סבירים בשוק היד שנייה, במיוחד לדגמים ישנים יותר.\n\n4. **Honda CRF250L**:\n   - אם אתה מוכן לשקול אופנוע קטן יותר, דגם זה משתלם מאוד.\n   - שוקל פחות, קל לתפעול עם ניסיון נמוך, ובמחיר קשה לנצח.\n\n5. **BMW F 650 GS**:\n   - דגם ישן יותר אך איכותי, יכול לשמש למשימות דו-שימושיות, יש לו גם שמירה על ערך טוב בשוק יד שנייה.\n\n### טיפים לרכישת אופנוע זול:\n- **בדוק את המצב**: כשאתה מחפש אופנוע יד שנייה, חשוב לבדוק את המצב המכני והטכני שלו. חפש בעיות פוטנציאליות ותשאול עם בעל האופנוע הקודם.\n- **שירותים ותיעוד**: ודא שהאופנוע עבר תחזוקה נאותה ויש תיעוד של זה.\n- **ניסיון רכיבה**: נסיעת מבחן היא קריטית – זכור לבדוק את נוחות העלייה על האופנוע.\n\nאם יש דגם מסוים שמעניין אותך, אשמח לעזור במידע נוסף!','2026-06-14 23:35:37'),(78,20,9,2,'משהו אוסטרלי?','2026-06-15 00:19:09'),(79,20,10,1,'אם אתה מחפש אופנוע דו-שימושי אוסטרלי, דרך מצוינת להתחיל היא להתמקד במותגים כמו **KTM** ו**Husqvarna**, ששני המותגים האלו הואשמו בסגנון אוסטרלי וידועים בגישהיהם לשטח ואופנועים דו-שימושיים. הנה כמה דגמים אוסטרליים ומקובלים:\n\n### אופנועים דו-שימושיים אוסטרליים:\n\n1. **KTM 690 Enduro R**\n   - אופנוע חזק עם יכולת שטח מצוינת.\n   - קל יחסית וקל לתמרון, מתאים לרוכבים עם קצת ניסיון.\n   - מערכת מתקדמת שמיועדת לשטח עם יכולות טובות בכביש.\n\n2. **Husqvarna 701 Enduro**\n   - דגם המציע ביצועים גבוהים בשטח, מרגיש קל ולא כבד.\n   - אופנוע חשמלי מאוד עם תחושה אוסטרלית ברורה.\n   - ניתן להשתמש בו בצורה נוחה גם בכבישים סלוליים.\n\n#### דגמים אחרים ואפשרויות רלוונטיות:\n\n3. **KTM 500 EXC-F**\n   - אופנוע בדו-שימושי, מאוד פופולרי בקרב רוכבי שטח.\n   - חזק מבחינת כוח, המצוין גם בכביש וגם בשטח.\n\n4. **Husqvarna 501 FE**\n   - גרסה עם מיקוד בשטח, אך ניתן להשתמש בה גם עבור נסיעות ארוכות.\n   - אופנוע איכותי ומתקדם טכנולוגית.\n\n### טיפים לרכישת אופנוע דו-שימושי אוסטרלי:\n- **שוק היד השנייה**: חפש מבצעים בשוק היד השנייה – ישנם דגמים רלוונטיים שניתן למצוא במחירים משתלמים.\n- **בדוק חילופים**: אם אתה מבקש רכישה מיד שנייה, הקפד לבדוק את המצב הכללי, התחזוקה ותיעוד.\n- **אביזרים**: פעמים רבות, בקטגוריה הזו, ניתן למצוא שיפורים או שדרוגים שהבעלים הקודמים הוסיפו.\n\nאם יש לך שאלות נוספות או אם אתה מתעניין בפרטיות אחרות, אני כאן לעזור!','2026-06-15 00:19:19'),(80,20,11,2,'משהו בסגנון ADV?','2026-06-15 00:21:23'),(81,20,12,1,'אופנועי **ADV** (אדוונצ\'ר) הם בחירה מצוינת עבור רוכבים המעוניינים בחווית רכיבה משולבת, בשטח ובכביש. הם מציעים נוחות רבה, יכולת שטח מרשימה ועמידות. הנה כמה דגמים פופולריים בסגנון ADV בסביבות 800 סמ\"ק שבטוח תוכל למצוא גם בשוק היד השנייה במחירים נוחים:\n\n### דגמי ADV פופולריים:\n\n1. **BMW F 850 GS**\n   - אופנוע שכלל את הטכנולוגיה המתקדמת של BMW, עם יכולות גבוהות בשטח ונסיעות ארוכות.\n   - מציע נוחות וגם ביצועים טובים בכביש ובשטח.\n   - ישנם דגמים משומשים שמציעים ערך מוסף.\n\n2. **Kawasaki Versys 650**\n   - אופנוע נוח מאוד לנסיעות ארוכות, מספק חווית רכיבה על הכביש ובשבילי שטח.\n   - ניתן למצוא במחירים נוחים בשוק היד השנייה.\n\n3. **Yamaha Tenere 700**\n   - דגם חזק שמסוגל לעמוד בעומסים ואידיאלי לנסיעות ארוכות.\n   - הוא מציע יתרון בשטח ויש המון רוכבים מרוצים ממדגם זה.\n\n4. **Suzuki V-Strom 650**\n   - אופנוע עורפי מקודמי, מציע נוחות גבוהה ויכולת שטח סבירה.\n   - מהווה אופציה אטרקטיבית במחירים נוחים יחסית.\n\n5. **KTM 790 Adventure**\n   - למרות שזה דגם חדש יותר, ישנם דגמים משומשים ואפשר למצוא אותם במחירי שוק טובים.\n   - מציעה ביצועים גבוהים בשטח עם טכנולוגיות מתקדמות.\n\n### טיפים לרכישת אופנוע ADV:\n- **נסיעת מבחן**: כמו בכל רכישה של אופנוע, קריטי לבצע נסיעת מבחן כדי להבין את נוחות הרכיבה.\n- **תחזוקה**: בדוק את המצב הכללי של האופנוע, ממשק תחזוקה ותיקונים שבוצעו.\n- **אביזרים**: רבים מבעלי האופנועים מחליפים חלקים נוספים (כמו תיקים, מדפים, צמיגים) – כדאי לבדוק מה יש כבר על האופנוע.\n\nאם יש לך שאלות נוספות או דגמים מסוימים שאתה שוקל, אל תהסס לשאול!','2026-06-15 00:21:30');
